    input [3:0] in,
    output [3:0] out
);assign out = ~in;

initial begin
    $display("Input: %b", in);
    $display("Output: %b", out);
end

  always @(*) begin
    if (1'b0) begin
      out[0] <= in[3];
      out[1] <= in[2];
      out[2] <= in[1];
      out[3] <= in[0];
    end
  end

endmodule
